// Flatten and sort all page blocks into a single tender_text string.
// Prioritise sections likely to contain eligibility criteria.
const doc = $input.first().json;
const blocks = doc.blocks || doc.page_blocks || [];

const ELIGIBILITY_KEYWORDS = [
  'eligibility', 'eligible', 'criteria', 'qualification',
  'shall', 'must', 'mandatory', 'required', 'turnover',
  'experience', 'similar work', 'registration', 'certificate'
];

// Sort by page then block order
const sorted = [...blocks].sort(
  (a, b) => (a.page_num - b.page_num) || ((a.block_index ?? 0) - (b.block_index ?? 0))
);

// Full text
const full_text = sorted.map(b => b.text || '').join('\n\n');

// Rough token estimate (1 token ≈ 4 chars)
const TOKEN_LIMIT = 12000;
const CHAR_LIMIT = TOKEN_LIMIT * 4;

let tender_text = full_text;

if (full_text.length > CHAR_LIMIT) {
  // Over budget — keep only eligibility-relevant blocks
  const relevant = sorted.filter(b => {
    const t = (b.text || '').toLowerCase();
    return ELIGIBILITY_KEYWORDS.some(kw => t.includes(kw));
  });
  tender_text = relevant.map(b => b.text || '').join('\n\n');

  // If still over, hard truncate
  if (tender_text.length > CHAR_LIMIT) {
    tender_text = tender_text.substring(0, CHAR_LIMIT);
  }
}

return [{
  json: {
    tender_text,
    tender_id: doc.tender_id || $('Webhook Trigger').first().json.tender_id,
    document_id: doc.id || $('Webhook Trigger').first().json.document_id,
    total_blocks: blocks.length,
    text_length: tender_text.length,
    truncated: full_text.length > CHAR_LIMIT
  }
}];

// Strip markdown fences and parse the JSON array from Mistral's response.
// Mistral-7b almost always wraps output in ```json ... ``` — handle it every time.

const response = $input.first().json;
const tender_id = $('Concatenate & Trim Text').first().json.tender_id;
const document_id = $('Concatenate & Trim Text').first().json.document_id;

let raw = response.choices?.[0]?.message?.content || '';

// Step 1: Strip markdown fences (```json ... ``` or ``` ... ```)
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

// Step 2: Find the first [ and last ] to isolate the array
const arrayStart = raw.indexOf('[');
const arrayEnd = raw.lastIndexOf(']');

if (arrayStart === -1 || arrayEnd === -1) {
  return [{ json: {
    parse_error: true,
    error: 'No JSON array found in response',
    raw_output: raw,
    tender_id,
    document_id
  }}];
}

raw = raw.substring(arrayStart, arrayEnd + 1);

// Step 3: Fix common Mistral JSON mistakes
// Trailing commas before ] or }
raw = raw.replace(/,\s*([\]\}])/g, '$1');
// Single quotes → double quotes (rare but happens)
raw = raw.replace(/'/g, '"');

try {
  const criteria = JSON.parse(raw);

  if (!Array.isArray(criteria)) {
    throw new Error('Parsed value is not an array');
  }

  if (criteria.length === 0) {
    throw new Error('Empty criteria array — model may have misunderstood the prompt');
  }

  // Validate each criterion has required fields
  const required = ['criterion_id', 'name', 'type', 'description', 'mandatory', 'source_section', 'confidence'];
  const invalid = criteria.filter(c => required.some(f => c[f] === undefined));

  if (invalid.length > 0) {
    return [{ json: {
      parse_error: true,
      error: `${invalid.length} criteria missing required fields`,
      raw_output: raw,
      partial_criteria: criteria,
      tender_id,
      document_id
    }}];
  }

  return [{ json: { criteria, parse_error: false, tender_id, document_id } }];

} catch (e) {
  return [{ json: {
    parse_error: true,
    error: e.message,
    raw_output: raw,
    tender_id,
    document_id
  }}];
}

