// Same parse logic as Node 5 — applied to the retry response
const response = $input.first().json;
const tender_id = $('Concatenate & Trim Text').first().json.tender_id;
const document_id = $('Concatenate & Trim Text').first().json.document_id;

let raw = response.choices?.[0]?.message?.content || '';
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

const arrayStart = raw.indexOf('[');
const arrayEnd = raw.lastIndexOf(']');

if (arrayStart === -1 || arrayEnd === -1) {
  // Both attempts failed — POST failure to FastAPI and stop
  return [{ json: {
    extraction_failed: true,
    error: 'Both extraction attempts failed to produce valid JSON',
    tender_id,
    document_id
  }}];
}

raw = raw.substring(arrayStart, arrayEnd + 1);
raw = raw.replace(/,\s*([\]\}])/g, '$1');

try {
  const criteria = JSON.parse(raw);
  if (!Array.isArray(criteria) || criteria.length === 0) throw new Error('Empty or non-array');
  return [{ json: { criteria, parse_error: false, tender_id, document_id } }];
} catch (e) {
  return [{ json: {
    extraction_failed: true,
    error: `Retry also failed: ${e.message}`,
    raw_output: raw,
    tender_id,
    document_id
  }}];
}

// Add UUIDs, order_index, and status to each criterion
// Merge from either the first-attempt or retry path
const input = $input.first().json;
const criteria = input.criteria || [];
const tender_id = input.tender_id;
const document_id = input.document_id;

const result = criteria.map((c, i) => ({
  id: crypto.randomUUID(),
  tender_id,
  document_id,
  order_index: i,
  status: 'pending_review',   // Officer must review before evaluation starts
  extracted_by: 'mistral-7b-instruct-q4',
  extracted_at: new Date().toISOString(),
  // Spread all model-extracted fields
  criterion_id: c.criterion_id || `C-${i + 1}`,
  name: c.name,
  type: c.type,
  description: c.description,
  threshold_value: c.threshold_value ?? null,
  threshold_unit: c.threshold_unit ?? null,
  mandatory: c.mandatory ?? null,
  source_section: c.source_section ?? null,
  source_text: c.source_text ?? null,
  confidence: c.confidence ?? 0.5,
  requires_human_review: (c.mandatory === null) || (c.confidence < 0.80)
}));

return [{ json: { tender_id, document_id, criteria: result, total: result.length } }];

